package com.payment.module.security

import android.content.Context
import android.content.SharedPreferences
import android.os.Build
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import android.util.Base64
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import com.payment.module.PaymentConfig
import com.payment.module.model.Transaction
import com.payment.module.model.WalletInfo
import java.security.KeyStore
import javax.crypto.Cipher
import javax.crypto.KeyGenerator
import javax.crypto.SecretKey
import javax.crypto.spec.GCMParameterSpec

class SecureStorageManager(private val context: Context) {

    private val gson = Gson()
    private val keyAlias = "PaymentModuleKey"
    private val androidKeyStore = "AndroidKeyStore"

    private val sharedPreferences: SharedPreferences by lazy {
        createSecurePreferences()
    }

    private fun createSecurePreferences(): SharedPreferences {
        return try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()

            EncryptedSharedPreferences.create(
                context,
                PaymentConfig.SHARED_PREFS_NAME,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (e: Exception) {
            // Fallback for older devices - use manual encryption
            context.getSharedPreferences(PaymentConfig.SHARED_PREFS_NAME, Context.MODE_PRIVATE)
        }
    }

    private fun getOrCreateSecretKey(): SecretKey {
        val keyStore = KeyStore.getInstance(androidKeyStore)
        keyStore.load(null)

        if (keyStore.containsAlias(keyAlias)) {
            val entry = keyStore.getEntry(keyAlias, null) as KeyStore.SecretKeyEntry
            return entry.secretKey
        }

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            androidKeyStore
        )

        val builder = KeyGenParameterSpec.Builder(
            keyAlias,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            builder.setUnlockedDeviceRequired(true)
        }

        keyGenerator.init(builder.build())
        return keyGenerator.generateKey()
    }

    fun encryptData(plainText: String): String {
        return try {
            val secretKey = getOrCreateSecretKey()
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(Cipher.ENCRYPT_MODE, secretKey)

            val iv = cipher.iv
            val encryptedBytes = cipher.doFinal(plainText.toByteArray(Charsets.UTF_8))

            val combined = ByteArray(iv.size + encryptedBytes.size)
            System.arraycopy(iv, 0, combined, 0, iv.size)
            System.arraycopy(encryptedBytes, 0, combined, iv.size, encryptedBytes.size)

            Base64.encodeToString(combined, Base64.NO_WRAP)
        } catch (e: Exception) {
            throw SecurityException("Failed to encrypt data", e)
        }
    }

    fun decryptData(encryptedText: String): String {
        return try {
            val secretKey = getOrCreateSecretKey()
            val combined = Base64.decode(encryptedText, Base64.NO_WRAP)

            val iv = combined.copyOfRange(0, 12)
            val encryptedBytes = combined.copyOfRange(12, combined.size)

            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            val spec = GCMParameterSpec(128, iv)
            cipher.init(Cipher.DECRYPT_MODE, secretKey, spec)

            String(cipher.doFinal(encryptedBytes), Charsets.UTF_8)
        } catch (e: Exception) {
            throw SecurityException("Failed to decrypt data", e)
        }
    }

    fun saveWalletInfo(walletInfo: WalletInfo) {
        val json = gson.toJson(walletInfo)
        val encrypted = encryptData(json)
        sharedPreferences.edit().putString(PaymentConfig.WALLET_BALANCE_KEY, encrypted).apply()
    }

    fun getWalletInfo(): WalletInfo {
        val encrypted = sharedPreferences.getString(PaymentConfig.WALLET_BALANCE_KEY, null)
            ?: return WalletInfo()
        return try {
            val json = decryptData(encrypted)
            gson.fromJson(json, WalletInfo::class.java)
        } catch (e: Exception) {
            WalletInfo()
        }
    }

    fun saveTransactionHistory(transactions: List<Transaction>) {
        val json = gson.toJson(transactions)
        val encrypted = encryptData(json)
        sharedPreferences.edit().putString(PaymentConfig.TRANSACTION_HISTORY_KEY, encrypted).apply()
    }

    fun getTransactionHistory(): List<Transaction> {
        val encrypted = sharedPreferences.getString(PaymentConfig.TRANSACTION_HISTORY_KEY, null)
            ?: return emptyList()
        return try {
            val json = decryptData(encrypted)
            val type = object : TypeToken<List<Transaction>>() {}.type
            gson.fromJson(json, type)
        } catch (e: Exception) {
            emptyList()
        }
    }

    fun clearAllData() {
        sharedPreferences.edit().clear().apply()
        try {
            val keyStore = KeyStore.getInstance(androidKeyStore)
            keyStore.load(null)
            keyStore.deleteEntry(keyAlias)
        } catch (e: Exception) {
            // Key might not exist
        }
    }
}

