package com.payment.module.security

object DataSanitizer {

    fun sanitizeAmount(amount: Double): Double {
        return Math.round(amount * 100.0) / 100.0
    }

    fun validateAmount(amount: Double): Boolean {
        return amount in com.payment.module.PaymentConfig.MIN_TRANSACTION_AMOUNT..com.payment.module.PaymentConfig.MAX_TRANSACTION_AMOUNT
    }

    fun sanitizeString(input: String): String {
        return input.replace(Regex("[<>\"'&;]"), "").trim()
    }

    fun maskCardNumber(cardNumber: String): String {
        if (cardNumber.length < 4) return "****"
        return "**** **** **** ${cardNumber.takeLast(4)}"
    }

    fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val name = parts[0]
        val domain = parts[1]
        val maskedName = if (name.length > 2) {
            "${name.first()}${"*".repeat(name.length - 2)}${name.last()}"
        } else {
            "*".repeat(name.length)
        }
        return "$maskedName@$domain"
    }

    fun validateProductId(productId: String): Boolean {
        return productId.matches(Regex("^[a-zA-Z0-9._-]+$")) && productId.length in 1..150
    }
}

