package com.payment.module.security

import android.util.Log

object SecurityAuditLogger {
    private const val TAG = "PaymentAudit"
    private val auditLog = mutableListOf<AuditEntry>()

    data class AuditEntry(
        val timestamp: Long = System.currentTimeMillis(),
        val event: String,
        val severity: Severity,
        val details: String = ""
    )

    enum class Severity {
        INFO, WARNING, CRITICAL
    }

    fun logEvent(event: String, severity: Severity = Severity.INFO, details: String = "") {
        val entry = AuditEntry(event = event, severity = severity, details = details)
        auditLog.add(entry)

        when (severity) {
            Severity.INFO -> Log.i(TAG, "$event: $details")
            Severity.WARNING -> Log.w(TAG, "$event: $details")
            Severity.CRITICAL -> Log.e(TAG, "$event: $details")
        }
    }

    fun getRecentLogs(count: Int = 50): List<AuditEntry> {
        return auditLog.takeLast(count)
    }

    fun clearLogs() {
        auditLog.clear()
    }
}

