class BillingManager(private val context: Context) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null
    private var purchaseDeferred: CompletableDeferred<PaymentResult<Purchase>>? = null

    private val _connectionState = MutableStateFlow(false)
    val connectionState: StateFlow<Boolean> = _connectionState.asStateFlow()

    private val _availableProducts = MutableStateFlow<List<ProductInfo>>(emptyList())
    val availableProducts: StateFlow<List<ProductInfo>> = _availableProducts.asStateFlow()

    private val pendingPurchaseCallbacks = mutableMapOf<String, (PaymentResult<Transaction>) -> Unit>()

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        startConnection()
    }

    private fun startConnection() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _connectionState.value = true
                    SecurityAuditLogger.logEvent(
                        "BillingConnection",
                        SecurityAuditLogger.Severity.INFO,
                        "Billing client connected successfully"
                    )
                } else {
                    _connectionState.value = false
                    SecurityAuditLogger.logEvent(
                        "BillingConnectionFailed",
                        SecurityAuditLogger.Severity.WARNING,
                        "Response code: ${billingResult.responseCode}"
                    )
                }
            }

            override fun onBillingServiceDisconnected() {
                _connectionState.value = false
                SecurityAuditLogger.logEvent(
                    "BillingDisconnected",
                    SecurityAuditLogger.Severity.WARNING,
                    "Billing service disconnected, will retry"
                )
                // Retry connection
                startConnection()
            }
        })
    }

